package com.chaobo.scm.supplier.infrastructure.persistence.contract;

import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.supplier.application.contract.*;import org.springframework.stereotype.Repository;import java.time.LocalDate;import java.util.*;
@Repository public class MyBatisPriceAgreementReadModel implements PriceAgreementReadModelPort {private final PriceAgreementQueryMapper mapper;public MyBatisPriceAgreementReadModel(PriceAgreementQueryMapper mapper){this.mapper=mapper;}public Optional<PriceAgreementView> detail(long id){var header=mapper.find(id);return header==null?Optional.empty():Optional.of(view(header));}public PageResult<PriceAgreementView> page(Long supplierId,String skuCode,int pageNo,int pageSize){return new PageResult<>(pageNo,pageSize,mapper.count(supplierId,skuCode),mapper.page(supplierId,skuCode,(pageNo-1)*pageSize,pageSize).stream().map(this::view).toList());}public Optional<PriceAgreementView.Line> activeLine(long supplierId,String skuCode,String currency,LocalDate date){var line=mapper.activeLine(supplierId,skuCode,currency,date);return line==null?Optional.empty():Optional.of(line(line));}private PriceAgreementView view(PriceAgreementQueryMapper.Header h){return new PriceAgreementView(h.id(),h.ref(),h.contractId(),h.quoteId(),h.supplierId(),h.currency(),h.from(),h.to(),h.status(),h.version(),mapper.lines(h.id()).stream().map(this::line).toList());}private PriceAgreementView.Line line(PriceAgreementQueryMapper.Line l){return new PriceAgreementView.Line(l.sku(),l.price(),l.tax(),l.moq(),l.days());}}
